# ── ADR Tablo A (Bölüm 3.2) yerel veri kaynağı ────────────────────────────
# adr_verisi.py, resmi ADR A Tablosundan üretilmiş UN No → Kemler kodu (tehlike
# tanımlama numarası), sınıf, ambalaj grubu ve tünel kodu sözlüğüdür. Dosya
# yoksa uygulama yine çalışır; sadece tablodan tamamlama yapılmaz.
try:
    from adr_verisi import ADR_TABLO
except Exception:
    ADR_TABLO = {}


def _norm_pg(v) -> str:
    """Ambalaj grubunu 'I/II/III' biçimine getirir ('PG II', '2', 'ii' vb. girişler için)."""
    s = str(v or "").upper().replace("PG", "").replace("AMBALAJ GRUBU", "").strip()
    return {"1": "I", "2": "II", "3": "III"}.get(s, s)


def adr_tablodan_tamamla(data: dict) -> dict:
    """BÖLÜM 14'ten AI'nın çekemediği alanları resmi ADR Tablo A'dan tamamlar.
    En sık eksik kalan alan turuncu plakanın ÜST yarısındaki tehlike tanımlama
    (Kemler) kodudur: MSDS'lerin çoğu bunu yazmaz, ama UN numarası biliniyorsa
    Tablo A'dan kesin olarak bulunur. Ayrıca boşsa sınıf, ambalaj grubu ve
    tünel kodu da doldurulur. AI'nın belgeden okuduğu değerlerin ÜZERİNE YAZMAZ."""
    try:
        if not ADR_TABLO or not isinstance(data, dict):
            return data
        adr = data.get("adr_bolum14")
        if not isinstance(adr, dict):
            return data
        m = re.search(r"(\d{3,4})", str(adr.get("un_numarasi") or ""))
        if not m:
            return data
        varyantlar = ADR_TABLO.get(m.group(1).zfill(4))
        if not varyantlar:
            return data

        # Aynı UN birden çok satırda olabilir (farklı ambalaj grubu → farklı kod).
        # Önce belgedeki ambalaj grubuyla, sonra ADR sınıfıyla eşleştir; olmazsa
        # Kemler kodu dolu ilk satırı al.
        secim = None
        pg = _norm_pg(adr.get("ambalaj_grubu"))
        if pg:
            pg_es = [v for v in varyantlar if v.get("pg") == pg]
            secim = next((v for v in pg_es if v.get("kemler")), pg_es[0] if pg_es else None)
        if secim is None and adr.get("adr_sinifi"):
            sn = str(adr["adr_sinifi"]).strip()
            sn_es = [v for v in varyantlar if str(v.get("sinif", "")).strip() == sn]
            secim = next((v for v in sn_es if v.get("kemler")), sn_es[0] if sn_es else None)
        if secim is None:
            secim = next((v for v in varyantlar if v.get("kemler")), varyantlar[0])

        eslesen = {"kemler_kodu": "kemler", "adr_sinifi": "sinif",
                   "ambalaj_grubu": "pg", "tunel_kodu": "tunel",
                   "ozel_hukumler": "ozel"}
        tamamlanan = []
        for alan, kaynak in eslesen.items():
            if not ok(adr.get(alan)) and secim.get(kaynak):
                adr[alan] = secim[kaynak]
                tamamlanan.append(alan)
        # Etiket listesi (5.2.2 plakaları) boşsa tablodan doldur — "6.1 +3" → ["6.1", "3"]
        if not adr.get("etiketler") and secim.get("etiket"):
            etiketler = [p.strip() for p in re.split(r"[+,/]", secim["etiket"]) if p.strip()]
            if etiketler:
                adr["etiketler"] = etiketler
                tamamlanan.append("etiketler")
        if "kemler_kodu" in tamamlanan:
            adr["_tablo_notu"] = ("Tehlike tanımlama (Kemler) kodu belgede yazmıyordu; "
                                  "UN numarasına göre resmi ADR Tablo A'dan eklendi.")
    except Exception:
        pass  # tamamlama hiçbir koşulda analizi düşürmemeli
    return data


def ok(v):
    return bool(v and str(v).strip() and str(v).strip() not in ("null", "None", "—", "-"))


def flatten_text(v):
    """AI bazen metin alanını sözlük/liste döndürür (örn. {'atik_isleme': '...'}).
    Bunu karta basılabilir düz, okunur metne çevirir; {' '} gibi ham işaretleri engeller."""
    if v is None:
        return ""
    if isinstance(v, str):
        return v.strip()
    if isinstance(v, (int, float, bool)):
        return str(v)
    if isinstance(v, (list, tuple)):
        parts = [flatten_text(x) for x in v]
        return " ".join(p for p in parts if p)
    if isinstance(v, dict):
        # Değerleri al; tek değer varsa direkt onu, çoksa cümleleri birleştir
        vals = [flatten_text(x) for x in v.values()]
        vals = [p for p in vals if p]
        return " ".join(vals)
    return str(v)


def normalize_summary(s: dict) -> dict:
    """Karta basılmadan önce tüm serbest-metin alanlarını düz metne indirger."""
    if not isinstance(s, dict):
        return {}
    s = dict(s)  # kopya
    # Üst düzey serbest metin alanları
    for key in ["depolama", "dokulmede_yapilacaklar", "bertaraf", "tehlike_sinifi",
                "urun_adi", "kimyasal_adi", "cas_numarasi", "formul", "uretici",
                "acil_telefon", "sinyal_kelimesi"]:
        if key in s and not isinstance(s[key], str):
            s[key] = flatten_text(s[key])
    # Ürün adına, PDF tablo satırının düzleşmesi yüzünden CAS No / revizyon
    # tarihi gibi komşu alanlar karışabiliyor. Bu temizlik hem kural tabanlı
    # hem de AI çıktısı için ortak noktada uygulanır (AI da zaman zaman
    # satırın tamamını ürün adı sanabiliyor).
    if isinstance(s.get("urun_adi"), str):
        s["urun_adi"] = _urun_adi_kes(s["urun_adi"])

    # İç içe nesnelerdeki metin alanları
    for grp in ["fiziksel_ozellikler", "saglik_tehlikeleri", "ilk_yardim", "yangin", "kkd"]:
        sub = s.get(grp)
        if isinstance(sub, dict):
            s[grp] = {k: (flatten_text(val) if not isinstance(val, str) else val)
                      for k, val in sub.items()}
    # ADR Bölüm 14 metin alanları
    adr = s.get("adr_bolum14")
    if isinstance(adr, dict):
        s["adr_bolum14"] = {k: (flatten_text(val) if not isinstance(val, (str, list)) else val)
                            for k, val in adr.items()}
    return s

def safe_filename(name: str, fallback: str = "MSDS_Ozet") -> str:
    """Ürün adını Windows dosya adına uygun, Türkçe karaktersiz hale getirir."""
    tr_map = str.maketrans("çğıöşüÇĞİÖŞÜ", "cgiosuCGIOSU")
    s = (name or "").translate(tr_map)
    s = re.sub(r"[^\w\s-]", "", s).strip()
    s = re.sub(r"\s+", "_", s)
    return s or fallback


# PDF adlarına eklenen, ürünü tanımlamayan kısaltmalar (MSDS_Aseton_TR.pdf,
# Aseton_SDS312580.pdf gibi). Bitişik sayı ekleri de kapsanır (SDS312580 → atılır).
# Not: (?i) Türkçe İ/ı'yı eşlemediği için İ içeren kelimeler karakter sınıfıyla yazılır.
_AD_KISALTMALARI = re.compile(
    r"(?i)\b(?:"
    r"(?:msds|sds|gbf|tds|sdb)\d*"                 # kısaltma + bitişik sayı (SDS312580)
    r"|t[üu]rk[çc]e"                                # turkce/turkçe/türkçe/türkce
    r"|[İIiı]ng[İIiı]l[İIiı]zce"                    # ingilizce/İNGİLİZCE
    r"|tr|tur|ing|eng|en|de"
    r")\b\.?")


def tds_dosyasi_mi(text: str) -> bool:
    """PDF'in MSDS değil TDS (Teknik Bilgi/Veri Formu) olup olmadığını anlar.
    Kural: belge başında TDS işaretleri VARSA ve MSDS/GBF işaretleri YOKSA → TDS'dir,
    analiz edilmeden atlanır. (İçinde 'TDS' kelimesi geçen gerçek bir MSDS yanlışlıkla
    atlanmasın diye MSDS işaretleri her zaman önceliklidir.)"""
    bas = (text or "")[:4000]
    msds_isareti = re.search(
        r"(?i)güvenl[İIiı]k\s+b[İIiı]lg[İIiı]\s+formu|safety\s+data\s+sheet|material\s+safety"
        r"|\bmsds\b|\bgbf\b|zararlılık\s+tanımlanması|hazards?\s+identification", bas)
    if msds_isareti:
        return False
    tds_isareti = re.search(
        r"(?i)\bTDS\b|tekn[İIiı]k\s+(?:b[İIiı]lg[İIiı]|ver[İIiı])\s+formu|technical\s+data\s+sheet"
        r"|ürün\s+tekn[İIiı]k\s+formu", bas)
    return bool(tds_isareti)


def cikti_adi_olustur(fname: str, urun_adi=None) -> str:
    """Çıktı (yazdır/PDF kaydet) dosya adını kurar: önce PDF adı, sonra belgedeki
    ürün adı ('PDFAdı - ÜrünAdı'). İkisi aynı isme işaret ediyorsa yalnızca PDF adı
    kullanılır. PDF adındaki MSDS/SDS/GBF/TR/ING/ENG gibi kısaltmalar isme katılmaz."""
    pdf = re.sub(r"(?i)\.pdf\s*$", "", str(fname or ""))
    pdf = pdf.replace("_", " ").replace("-", " ")
    pdf = _AD_KISALTMALARI.sub(" ", pdf)
    pdf = re.sub(r"\s+", " ", pdf).strip(" .-–")
    urun = re.sub(r"\s+", " ", flatten_text(urun_adi or "")).strip()

    def _norm(x):
        # Karşılaştırma için: Türkçe İ/ı dahil küçük harfe indir, harf/rakam dışını at
        x = x.replace("İ", "i").replace("I", "ı").lower()
        return re.sub(r"[^0-9a-zçğıöşü]", "", x)

    if pdf and urun and _norm(pdf) != _norm(urun):
        return f"{pdf} - {urun}"
    return pdf or urun or "MSDS_Ozet"

