# ── PDF METİN ÇIKAR ────────────────────────────────────────────
def extract_pdf_text(file_bytes: bytes) -> str:
    with pdfplumber.open(io.BytesIO(file_bytes)) as pdf:
        pages = []
        for i, page in enumerate(pdf.pages):
            text = page.extract_text()
            if text:
                pages.append(f"[Sayfa {i+1}]\n{text}")
        return "\n\n".join(pages)


