def kart_ac_widget(card_html: str, btn_id: str, label: str = "🖼️ Kartı Aç") -> str:
    """Kart HTML'ini BLOB URL ile yeni sekmede açan buton bileşeni döndürür.
    data: URL'leri tarayıcılar üst düzey gezinmede engeller; blob: URL takılmaz."""
    b64 = base64.b64encode(card_html.encode("utf-8")).decode()
    return f"""
<button id="{btn_id}" style="width:100%;padding:7px 4px;background:#1565c0;color:#fff;
  border:none;border-radius:6px;cursor:pointer;font-size:13px;font-weight:500;">{label}</button>
<script>
(function(){{
  var b64 = "{b64}";
  function b64ToBlob(b64Data){{
    var byteChars = atob(b64Data);
    var bytes = new Uint8Array(byteChars.length);
    for (var i=0; i<byteChars.length; i++) bytes[i] = byteChars.charCodeAt(i);
    return new Blob([bytes], {{type: "text/html"}});
  }}
  var btn = document.getElementById("{btn_id}");
  if (btn) {{
    btn.addEventListener("click", function(){{
      try {{
        var blob = b64ToBlob(b64);
        var url = URL.createObjectURL(blob);
        var win = window.open(url, "_blank");
        if (!win) {{
          var a = document.createElement("a");
          a.href = url; a.target = "_blank"; a.rel = "noopener";
          document.body.appendChild(a); a.click(); a.remove();
        }}
        setTimeout(function(){{ URL.revokeObjectURL(url); }}, 60000);
      }} catch(e) {{ alert("Kart açılamadı: " + e.message); }}
    }});
  }}
}})();
</script>
"""


def analyze_with_failover(text, chain, models, keys, ollama_url, exhausted, on_switch=None):
    """Metni zincirdeki (chain) motorlarla sırayla dener.
    - GÜNLÜK kota dolan motor 'exhausted'a eklenir, bir daha denenmez, sıradakine geçilir.
    - DAKİKALIK limit (TPM/RPM) yiyen motor tükenmiş SAYILMAZ; call_* fonksiyonları zaten
      bekleyip tekrar dener. Yine de takılırsa o dosyada sıradakine geçilir ama motor açık kalır.
    Döner: (data, kullanılan_engine). Hepsi tükenirse son hatayı yükseltir.

    TOKEN TASARRUFU: Aynı belge metni (text) + aynı motor zinciri (chain) + aynı
    model ayarları (models) daha önce işlendiyse, sonuç .ai_cache/ klasöründen
    okunur ve HİÇBİR API isteği gönderilmez. API anahtarları (keys) cache
    anahtarına dahil EDİLMEZ; böylece anahtarını değiştirsen bile aynı belge
    için cache geçerli kalır.
    """

    def _gercek_analiz():
        last_err = None
        for eng in chain:
            if eng in exhausted:
                continue
            try:
                if on_switch:
                    on_switch(eng)
                data = call_ai(
                    text, eng, models.get(eng, ""),
                    ollama_url=ollama_url,
                    gemini_api_key=keys.get("gemini", ""),
                    groq_api_key=keys.get("groq", ""),
                    openai_api_key=keys.get("openai", ""),
                    claude_api_key=keys.get("claude", ""),
                    openrouter_api_key=keys.get("openrouter", ""),
                )
                # Kaynak belge İngilizce (veya başka bir dil) ise ve kullanılan
                # motor bunu Türkçe'ye çevirmediyse (özellikle 'kural' modu,
                # veya bazen küçük/hızlı modeller), ek küçük bir istekle çevir.
                data = sonucu_turkceye_cevir(data, chain, models, keys, ollama_url, exhausted)
                return {"data": data, "used_eng": eng}
            except Exception as e:
                last_err = e
                if _is_daily_exhausted_error(e):
                    # Günlük kota doldu → bu motoru oturum boyunca atla
                    exhausted.add(eng)
                    continue
                elif _is_minute_limit_error(e):
                    # Dakikalık limit: bu dosyada sıradakini dene ama motoru tüketme
                    continue
                else:
                    # Kota dışı hata (bozuk PDF, ağ vb.) → üst katman ele alsın
                    raise
        if last_err:
            raise last_err
        raise RuntimeError("Kullanılabilir AI motoru yok (anahtar girilmemiş olabilir).")

    # Cache anahtarı: belge metni + hangi motorlar/modeller denendiği.
    # API anahtarları BİLEREK dahil edilmiyor (anahtar değişse de cache geçerli kalsın).
    cache_key = {
        "text": text,
        "chain": list(chain),
        "models": {k: models.get(k, "") for k in chain},
    }

    sonuc, cache_hit = cached_call(
        key_source=cache_key,
        fn=_gercek_analiz,
        namespace="msds_analiz",
    )

    if cache_hit and on_switch:
        on_switch(f"{sonuc['used_eng']} (cache'ten - 0 token)")

    return sonuc["data"], sonuc["used_eng"]


def build_excel_summary(records: list) -> bytes:
    """Toplu işlem sonuçlarını tek bir Excel (xlsx) dosyasına özetler — bir PDF, bir satır."""
    from openpyxl import Workbook
    from openpyxl.styles import Font, PatternFill, Alignment
    from openpyxl.utils import get_column_letter

    def cell(v):
        """Her değeri Excel'in kabul edeceği düz metne çevirir (liste/dict/sayı dahil)."""
        if v is None:
            return ""
        if isinstance(v, str):
            return v
        if isinstance(v, (int, float, bool)):
            return v
        if isinstance(v, (list, tuple)):
            return ", ".join(cell(x) if not isinstance(x, str) else x for x in v if x not in (None, ""))
        if isinstance(v, dict):
            return ", ".join(f"{k}: {cell(val)}" for k, val in v.items() if val not in (None, ""))
        return str(v)

    def join_list(v, sep=", "):
        """Liste bekleyen alanlar için: liste değilse de güvenli string döndürür."""
        if v is None:
            return ""
        if isinstance(v, str):
            return v
        if isinstance(v, (list, tuple)):
            return sep.join(cell(x) if not isinstance(x, str) else x for x in v if x not in (None, ""))
        return cell(v)

    wb = Workbook()
    ws = wb.active
    ws.title = "MSDS Özet"

    headers = ["Dosya", "Ürün Adı", "Kimyasal Adı", "CAS No", "Üretici",
               "Sinyal Kelimesi", "GHS Piktogramları", "Tehlike Sınıfı",
               "H İfadeleri", "UN Numarası", "ADR Sınıfı", "Ambalaj Grubu", "Durum"]
    ws.append(headers)
    header_fill = PatternFill(start_color="1A237E", end_color="1A237E", fill_type="solid")
    for col_idx in range(1, len(headers) + 1):
        c = ws.cell(row=1, column=col_idx)
        c.font = Font(color="FFFFFF", bold=True)
        c.fill = header_fill
        c.alignment = Alignment(vertical="center")

    for rec in records:
        if rec.get("error"):
            ws.append([cell(rec.get("filename")), "", "", "", "", "", "", "", "", "", "", "",
                       f"HATA: {cell(rec.get('error'))}"])
            continue
        s = rec.get("data") or {}
        adr = s.get("adr_bolum14") or {}
        if not isinstance(adr, dict):
            adr = {}
        ws.append([
            cell(rec.get("filename")),
            cell(s.get("urun_adi")),
            cell(s.get("kimyasal_adi")),
            cell(s.get("cas_numarasi")),
            cell(s.get("uretici")),
            cell(s.get("sinyal_kelimesi")),
            join_list(s.get("ghs_piktogramlari")),
            cell(s.get("tehlike_sinifi")),
            join_list(s.get("h_ifadeleri"), "; "),
            cell(adr.get("un_numarasi")),
            cell(adr.get("adr_sinifi")),
            cell(adr.get("ambalaj_grubu")),
            "Tamam"
        ])

    widths = [24, 26, 20, 14, 18, 13, 18, 16, 32, 13, 11, 12, 10]
    for i, w in enumerate(widths, 1):
        ws.column_dimensions[get_column_letter(i)].width = w
    ws.freeze_panes = "A2"

    buf = io.BytesIO()
    wb.save(buf)
    return buf.getvalue()


def _extract_card(full_html: str) -> str:
    """Tek kartın tam #card bloğunu ayıklar. Kart her zaman gövdenin sonunda,
    #card ile </body> arasında yer alır (buton ve script no-print/head'de kalır)."""
    start = full_html.find('<div id="card"')
    if start == -1:
        return full_html
    end = full_html.rfind('</body>')
    if end == -1 or end <= start:
        return full_html[start:]
    return full_html[start:end].rstrip()


def build_combined_html(records: list) -> str:
    """Tüm ürün kartlarını TEK HTML dosyasında, her ürün ayrı yazdırma sayfasında birleştirir.
    Açıp 'Yazdır → PDF Kaydet' dendiğinde her ürün ayrı bir A4 sayfası olur."""
    cards = []
    for rec in records:
        if "html" not in rec:
            continue
        card_html = _extract_card(rec["html"])
        cards.append(card_html)

    if not cards:
        return "<html><body><p>Gösterilecek kart yok.</p></body></html>"

    pages = ""
    for i, c in enumerate(cards):
        # id="card" HTML'de benzersiz olmalı; birden fazla kart birleşince class'a çevir
        c = c.replace('id="card"', 'class="card"', 1)
        pages += f'<div class="card-page">{c}</div>'

    return f"""<!DOCTYPE html>
<html lang="tr"><head>
<meta charset="UTF-8">
<title>MSDS Toplu Ozet</title>
<style>
@page {{ size: A4 portrait; margin: 8mm; }}
*{{box-sizing:border-box}}
body{{font-family:system-ui,Arial,sans-serif;margin:0;padding:16px;background:#f0f2f5;}}
.card-page{{ display:block; margin:0 auto 24px; max-width:920px; }}
.card-page .card{{ margin:0 auto; }}
@media print {{
  .no-print{{display:none!important}}
  body{{padding:0;background:#fff;}}
  .card-page{{
    display:block;
    break-inside:avoid;
    page-break-inside:avoid;
    break-after:page;
    page-break-after:always;
    margin:0!important;max-width:none!important;
  }}
  .card-page:last-child{{ break-after:auto;page-break-after:auto; }}
  .card-page .card{{
    box-shadow:none!important;border:none!important;max-width:none!important;
  }}
}}
</style></head><body>
<div class="no-print" style="max-width:920px;margin:0 auto 16px;text-align:center;">
  <button onclick="window.print()" style="padding:8px 20px;background:#1565c0;color:#fff;border:none;border-radius:4px;cursor:pointer;font-size:13px;">🖨️ Tümünü Yazdır / PDF Kaydet ({len(cards)} ürün)</button>
  <div style="font-size:12px;color:#888;margin-top:6px;">Her ürün ayrı sayfada yazdırılır. Yazdırma penceresinde kâğıt: A4 seçili olsun.</div>
</div>
{pages}
</body></html>"""


def html_to_pdf_bytes(html: str):
    """Birleşik HTML'i PDF'e çevirmeyi dener. Ortamda bir motor yoksa None döner
    (o zaman kullanıcı HTML'i yazdırarak PDF alır)."""
    # 1) Playwright (varsa en yüksek kalite)
    try:
        from playwright.sync_api import sync_playwright
        with sync_playwright() as p:
            b = p.chromium.launch()
            pg = b.new_page()
            pg.set_content(html, wait_until="networkidle")
            pg.wait_for_timeout(300)
            pdf = pg.pdf(format="A4", print_background=True, prefer_css_page_size=True,
                         margin={"top": "8mm", "bottom": "8mm", "left": "8mm", "right": "8mm"})
            b.close()
            return pdf
    except Exception:
        pass
    # 2) WeasyPrint (varsa)
    try:
        from weasyprint import HTML as _WHTML
        return _WHTML(string=html).write_pdf()
    except Exception:
        pass
    return None


def check_ollama(base_url: str):
    try:
        r = requests.get(f"{base_url.rstrip('/')}/api/tags", timeout=3)
        if r.ok:
            return True, [m["name"] for m in r.json().get("models", [])]
    except Exception:
        pass
    return False, []


